-- ============================================================================
-- Файл: 08_stage1_form_test_data.sql
-- Назначение: полностью перезаполняет тестовые данные верхней части формы
-- медицинского приёма после применения миграции 0009_previsit_form_schema.
--
-- Файл изменяет только:
--   1) appointments.age_at_appointment;
--   2) surveys;
--   3) examinations.
--
-- Не изменяются лабораторные исследования, УЗИ, KDIGO, назначения,
-- расписание и структурированные диагнозы МКБ-10.
--
-- Предусловия:
--   - база обновлена до миграции 0009_previsit_form_schema;
--   - исходный демонстрационный файл 04 уже создал пациентов и приёмы 1–17.
--
-- Файл повторно запускаемый: INSERT ... ON CONFLICT обновляет эталонные строки
-- и не создаёт дубли.
-- ============================================================================

BEGIN;

-- --------------------------------------------------------------------------
-- 0. Явная проверка предусловий.
-- --------------------------------------------------------------------------
DO $$
BEGIN
    IF (SELECT COUNT(*) FROM appointments WHERE id BETWEEN 1 AND 17) <> 17 THEN
        RAISE EXCEPTION
            'Ожидались демонстрационные приёмы с id 1–17. '
            'Сначала загрузите исходные тестовые данные файла 04.';
    END IF;

    IF NOT EXISTS (
        SELECT 1
        FROM information_schema.columns
        WHERE table_schema = current_schema()
          AND table_name = 'appointments'
          AND column_name = 'age_at_appointment'
    ) THEN
        RAISE EXCEPTION
            'Миграция 0009_previsit_form_schema ещё не применена';
    END IF;
END
$$;

-- --------------------------------------------------------------------------
-- 1. ВОЗРАСТ НА ДАТУ ПРИЁМА.
-- Возраст вычисляется, а не копируется из искусственных старых значений.
-- --------------------------------------------------------------------------
UPDATE appointments AS a
SET age_at_appointment = EXTRACT(
    YEAR FROM age(a.appointment_date::date, p.birth_date)
)::smallint
FROM patients AS p
WHERE p.id = a.patient_id
  AND a.id BETWEEN 1 AND 17;

-- --------------------------------------------------------------------------
-- 2. ОПРОС: жалобы, анамнез жизни и анамнез данного заболевания.
-- Русские названия столбцов указаны рядом с техническими именами.
-- --------------------------------------------------------------------------
INSERT INTO surveys (
    appointment_id,                         -- Приём
    complaints,                             -- Жалобы
    education_and_professional_history,     -- Образование и профессиональный анамнез
    housing_conditions,                     -- Жилищные условия
    past_diseases,                          -- Перенесённые заболевания
    habitual_intoxications,                 -- Привычные интоксикации
    gynecological_history,                  -- Гинекологический анамнез
    heredity,                               -- Наследственность: отметка
    heredity_description,                   -- Наследственность: описание
    family_life,                            -- Семейная жизнь
    allergological_history,                 -- Аллергологический анамнез
    epidemiological_history,                -- Эпидемиологический анамнез
    insurance_history,                      -- Страховой анамнез
    disease_onset,                          -- Начало болезни
    disease_course                          -- Течение заболевания
)
VALUES
    (1, 'Головные боли, слабость, отёки голеней и стоп.', 'Среднее профессиональное образование. Слесарь-ремонтник промышленного оборудования; длительная работа в условиях шума и контакта с техническими маслами.', 'Проживает с супругой в благоустроенной квартире, санитарно-бытовые условия удовлетворительные.', 'Артериальная гипертензия с 2010 года, хронический пиелонефрит с 2015 года. Операций и гемотрансфузий не было.', 'Курит около 20 сигарет в сутки в течение 30 лет. Алкоголь употребляет эпизодически.', NULL, TRUE, 'У матери артериальная гипертензия, у отца сахарный диабет 2 типа.', 'Женат, проживает совместно с супругой, двое взрослых детей.', 'Аллергические реакции на лекарства и пищевые продукты отрицает.', 'Контакты с инфекционными больными, туберкулёз и вирусные гепатиты отрицает.', 'Работает. За последний год временная нетрудоспособность по поводу повышения артериального давления.', 'Повышение артериального давления отмечает с 2010 года. Изменения мочи и снижение функции почек выявлены при обследовании в 2020 году.', 'Состояние относительно стабильное. Артериальное давление контролируется нерегулярно; к вечеру появляются отёки.'),
    (2, 'Усиление головных болей, отёки нижних конечностей, одышка при нагрузке.', 'Среднее профессиональное образование. Слесарь-ремонтник промышленного оборудования; длительная работа в условиях шума и контакта с техническими маслами.', 'Проживает с супругой в благоустроенной квартире, санитарно-бытовые условия удовлетворительные.', 'Артериальная гипертензия с 2010 года, хронический пиелонефрит с 2015 года. Операций и гемотрансфузий не было.', 'Курит около 20 сигарет в сутки в течение 30 лет. Алкоголь употребляет эпизодически.', NULL, TRUE, 'У матери артериальная гипертензия, у отца сахарный диабет 2 типа.', 'Женат, проживает совместно с супругой, двое взрослых детей.', 'Аллергические реакции на лекарства и пищевые продукты отрицает.', 'Контакты с инфекционными больными, туберкулёз и вирусные гепатиты отрицает.', 'Работает. За последний год временная нетрудоспособность по поводу повышения артериального давления.', 'Повышение артериального давления отмечает с 2010 года. Изменения мочи и снижение функции почек выявлены при обследовании в 2020 году.', 'За последние три месяца отмечает ухудшение контроля артериального давления и нарастание отёков.'),
    (3, 'Выраженная слабость, головные боли, отёки нижних конечностей и лица.', 'Среднее профессиональное образование. Слесарь-ремонтник промышленного оборудования; длительная работа в условиях шума и контакта с техническими маслами.', 'Проживает с супругой в благоустроенной квартире, санитарно-бытовые условия удовлетворительные.', 'Артериальная гипертензия с 2010 года, хронический пиелонефрит с 2015 года. Операций и гемотрансфузий не было.', 'Курит около 20 сигарет в сутки в течение 30 лет. Алкоголь употребляет эпизодически.', NULL, TRUE, 'У матери артериальная гипертензия, у отца сахарный диабет 2 типа.', 'Женат, проживает совместно с супругой, двое взрослых детей.', 'Аллергические реакции на лекарства и пищевые продукты отрицает.', 'Контакты с инфекционными больными, туберкулёз и вирусные гепатиты отрицает.', 'Работает. За последний год временная нетрудоспособность по поводу повышения артериального давления.', 'Повышение артериального давления отмечает с 2010 года. Изменения мочи и снижение функции почек выявлены при обследовании в 2020 году.', 'Несмотря на терапию, сохраняются высокое артериальное давление и отёчный синдром; функция почек ухудшается.'),
    (4, 'Жажда, сухость во рту, утренняя отёчность лица.', 'Среднее медицинское образование. Работает медицинской сестрой в процедурном кабинете.', 'Проживает с семьёй в благоустроенной квартире, бытовые условия хорошие.', 'Сахарный диабет 2 типа с 2015 года, ожирение, диабетическая нефропатия с 2018 года.', 'Не курит. Алкоголь не употребляет.', 'Менархе с 13 лет, цикл регулярный. Две беременности, двое родов. Менопаузы нет.', TRUE, 'У матери сахарный диабет 2 типа и артериальная гипертензия.', 'Замужем, проживает с супругом и ребёнком.', 'Отмечает кожную сыпь на пенициллины; пищевую аллергию отрицает.', 'Профессиональный контакт с пациентами; средства индивидуальной защиты использует. Вирусные гепатиты и туберкулёз отрицает.', 'Работает. Имеет полис ОМС, эпизоды временной нетрудоспособности по поводу декомпенсации сахарного диабета.', 'Сахарный диабет диагностирован в 2015 году. Альбуминурия впервые выявлена в 2018 году, затем отмечено постепенное снижение СКФ.', 'Гликемический контроль нестабильный, периодически возникает утренняя отёчность.'),
    (5, 'Усиление жажды, слабость, отёки ног.', 'Среднее медицинское образование. Работает медицинской сестрой в процедурном кабинете.', 'Проживает с семьёй в благоустроенной квартире, бытовые условия хорошие.', 'Сахарный диабет 2 типа с 2015 года, ожирение, диабетическая нефропатия с 2018 года.', 'Не курит. Алкоголь не употребляет.', 'Менархе с 13 лет, цикл регулярный. Две беременности, двое родов. Менопаузы нет.', TRUE, 'У матери сахарный диабет 2 типа и артериальная гипертензия.', 'Замужем, проживает с супругом и ребёнком.', 'Отмечает кожную сыпь на пенициллины; пищевую аллергию отрицает.', 'Профессиональный контакт с пациентами; средства индивидуальной защиты использует. Вирусные гепатиты и туберкулёз отрицает.', 'Работает. Имеет полис ОМС, эпизоды временной нетрудоспособности по поводу декомпенсации сахарного диабета.', 'Сахарный диабет диагностирован в 2015 году. Альбуминурия впервые выявлена в 2018 году, затем отмечено постепенное снижение СКФ.', 'В последние месяцы повысились показатели глюкозы и усилился отёчный синдром.'),
