    complaints = EXCLUDED.complaints,
    education_and_professional_history = EXCLUDED.education_and_professional_history,
    housing_conditions = EXCLUDED.housing_conditions,
    past_diseases = EXCLUDED.past_diseases,
    habitual_intoxications = EXCLUDED.habitual_intoxications,
    gynecological_history = EXCLUDED.gynecological_history,
    heredity = EXCLUDED.heredity,
    heredity_description = EXCLUDED.heredity_description,
    family_life = EXCLUDED.family_life,
    allergological_history = EXCLUDED.allergological_history,
    epidemiological_history = EXCLUDED.epidemiological_history,
    insurance_history = EXCLUDED.insurance_history,
    disease_onset = EXCLUDED.disease_onset,
    disease_course = EXCLUDED.disease_course;

