INSERT INTO examinations (
    appointment_id,
    general_condition,
    consciousness,
    bed_position,
    bed_position_details,
    body_build,
    height,
    weight,
    bmi,
    constitution_type,
    skin_and_mucous_membranes,
    edema_location,
    lymph_nodes,
    thyroid_gland,
    musculoskeletal_system,
    body_temperature,
    systolic_pressure,
    diastolic_pressure,
    bp_note,
    heart_rate,
    veins_condition,
    lung_auscultation,
    abdomen,
    kidney_palpation,
    kidney_palpation_details,
    pasternatsky_result,
    pasternatsky_side
)
SELECT
    appointment_id,
    general_condition,
    consciousness,
    bed_position,
    bed_position_details,
    body_build,
    height,
    weight,
    ROUND((weight / POWER(height / 100.0, 2))::numeric, 2) AS bmi,
    constitution_type,
    skin_and_mucous_membranes,
    edema_location,
    lymph_nodes,
    thyroid_gland,
    musculoskeletal_system,
    body_temperature,
    systolic_pressure,
    diastolic_pressure,
    bp_note,
    heart_rate,
    veins_condition,
    lung_auscultation,
    abdomen,
    kidney_palpation,
    kidney_palpation_details,
    pasternatsky_result,
    pasternatsky_side
FROM source
ON CONFLICT (appointment_id) DO UPDATE SET
    general_condition = EXCLUDED.general_condition,
    consciousness = EXCLUDED.consciousness,
    bed_position = EXCLUDED.bed_position,
    bed_position_details = EXCLUDED.bed_position_details,
    body_build = EXCLUDED.body_build,
    height = EXCLUDED.height,
    weight = EXCLUDED.weight,
    bmi = EXCLUDED.bmi,
    constitution_type = EXCLUDED.constitution_type,
    skin_and_mucous_membranes = EXCLUDED.skin_and_mucous_membranes,
    edema_location = EXCLUDED.edema_location,
    lymph_nodes = EXCLUDED.lymph_nodes,
    thyroid_gland = EXCLUDED.thyroid_gland,
    musculoskeletal_system = EXCLUDED.musculoskeletal_system,
    body_temperature = EXCLUDED.body_temperature,
    systolic_pressure = EXCLUDED.systolic_pressure,
    diastolic_pressure = EXCLUDED.diastolic_pressure,
    bp_note = EXCLUDED.bp_note,
    heart_rate = EXCLUDED.heart_rate,
    veins_condition = EXCLUDED.veins_condition,
    lung_auscultation = EXCLUDED.lung_auscultation,
    abdomen = EXCLUDED.abdomen,
    kidney_palpation = EXCLUDED.kidney_palpation,
    kidney_palpation_details = EXCLUDED.kidney_palpation_details,
    pasternatsky_result = EXCLUDED.pasternatsky_result,
    pasternatsky_side = EXCLUDED.pasternatsky_side;

COMMIT;

-- Краткий итог после заполнения.
SELECT
    (SELECT COUNT(*) FROM appointments WHERE id BETWEEN 1 AND 17 AND age_at_appointment IS NOT NULL) AS appointments_with_age,
    (SELECT COUNT(*) FROM surveys WHERE appointment_id BETWEEN 1 AND 17) AS surveys_filled,
    (SELECT COUNT(*) FROM examinations WHERE appointment_id BETWEEN 1 AND 17) AS examinations_filled;
